(function(){"use strict";const w={name:"Propano",A:3.92828,B:803.997,C_ant:247.04,chi:.5,m_ratio:4.5},D={name:"Isobutano",A:3.93747,B:893.527,C_ant:248.87,chi:.6,m_ratio:5.2};function F(e,o){return 10**(o.A-o.B/(e+o.C_ant))*100}function G(e,o,c,i){const n=1-e;return e<=1e-10?1e9:Math.log(e)+(1-1/c)*n+i*n*n-Math.log(o)}function I(e,o,c=1e-12,i=200){let n=o;for(let l=0;l<i;l++){const u=e(n);if(Math.abs(u)<c)return n;const A=Math.max(Math.abs(n)*1e-8,1e-14),C=(e(n+A)-u)/A;if(Math.abs(C)<1e-30)break;n=n-u/C,n<0&&(n=1e-15),n>1&&(n=1-1e-15)}return n}function q(e,o){const{temp_c:c,vacio_mbar:i,log_D_base:n,alpha:l,C_0_pct:u}=o,A=o.L_mm/1e3,C=i/10,R=F(c,e),P=10**n,y=u/100;let S=C/R;S>=1&&(S=.9999);let _;try{_=I(r=>G(r,S,e.m_ratio,e.chi),1e-5)}catch{_=1e-6}_<0&&(_=1e-7);const s=30,f=A/s,B=f*f,g=8e5,E=_*1e6,j=E*1.02,z=2e3,a=new Float64Array(s).fill(y),m=new Float64Array(s),h=new Float64Array(s);let p=y,b=B/(3*P*Math.exp(l*p)),L=b/f,x=0;const v=[],O=[],H=200;let k=0;for(let r=0;r<g;r++){if(r%z===0&&r>0){p=0;for(let t=0;t<s;t++)a[t]>p&&(p=a[t]);b=B/(3*P*Math.exp(l*p)),L=b/f}for(let t=0;t<s;t++)h[t]=P*Math.exp(l*a[t]);m[0]=a[0],m[s-1]=_;for(let t=1;t<s-1;t++){const d=(h[t]+h[t+1])*.5*(a[t+1]-a[t])/f,M=(h[t]+h[t-1])*.5*(a[t]-a[t-1])/f;m[t]=a[t]+L*(d-M)}if(m[0]=m[1],a.set(m),x+=b,x>=k||r===g-1){const t=x/3600;let d=0;for(let T=0;T<s;T++)d+=a[T];const M=d/s*1e6;if(v.push(t),O.push(M),v.length>10&&M<=j)break;const U=x*(g/(r+1));k=x+U/H}}return{tiempos_h:v,ppm_promedio:O,c_eq_ppm:E,gas:e.name}}function N(e){return[q(w,e),q(D,e)]}self.onmessage=e=>{const{id:o,input:c}=e.data,i=N(c);self.postMessage({id:o,results:i})}})();
